// ============================================================
// Node 4: Schema Validation
// Validates the LLM response before routing to catch
// malformed or incomplete output.
// ============================================================

const input = $input.first().json;

// Parse LLM response — handle both direct JSON and wrapped message objects
let llmOutput;
try {
  const content = input.message?.content || input.text || input.content || JSON.stringify(input);
  llmOutput = typeof content === 'string' ? JSON.parse(content) : content;
} catch (e) {
  return [{
    json: {
      request_id: input.request_id,
      source: input.source,
      raw_message: input.raw_message,
      timestamp: input.timestamp,
      validation_passed: false,
      escalation_flag: true,
      destination_queue: 'Escalation Queue',
      escalation_reason: 'Failed to parse LLM response as JSON: ' + e.message,
      category: 'Unknown',
      priority: 'High',
      confidence_score: 0,
      core_issue: 'LLM output could not be parsed',
      extracted_entities: {},
      urgency_signal: 'High',
      human_summary: 'The AI classification failed to produce valid output. Manual review required.',
      validation_errors: [e.message]
    }
  }];
}

const VALID_CATEGORIES = ['Bug Report', 'Feature Request', 'Billing Issue', 'Technical Question', 'Incident/Outage'];
const VALID_PRIORITIES = ['Low', 'Medium', 'High'];
const errors = [];

if (!VALID_CATEGORIES.includes(llmOutput.category)) {
  errors.push(`Invalid category: '${llmOutput.category}'`);
}
if (!VALID_PRIORITIES.includes(llmOutput.priority)) {
  errors.push(`Invalid priority: '${llmOutput.priority}'`);
}

const score = parseFloat(llmOutput.confidence_score);
if (isNaN(score) || score < 0 || score > 1) {
  errors.push(`Invalid confidence_score: '${llmOutput.confidence_score}'`);
}

if (!llmOutput.core_issue || typeof llmOutput.core_issue !== 'string' || llmOutput.core_issue.trim() === '') {
  errors.push('Missing or empty core_issue');
}
if (!llmOutput.human_summary || typeof llmOutput.human_summary !== 'string' || llmOutput.human_summary.trim() === '') {
  errors.push('Missing or empty human_summary');
}

const validationPassed = errors.length === 0;

return [{
  json: {
    request_id: input.request_id,
    source: input.source,
    raw_message: input.raw_message,
    timestamp: input.timestamp,
    category: llmOutput.category || 'Unknown',
    priority: llmOutput.priority || 'High',
    confidence_score: parseFloat(llmOutput.confidence_score) || 0,
    core_issue: llmOutput.core_issue || 'Unable to determine',
    extracted_entities: llmOutput.extracted_entities || {},
    urgency_signal: llmOutput.urgency_signal || 'High',
    human_summary: llmOutput.human_summary || 'Manual review required.',
    validation_passed: validationPassed,
    validation_errors: errors,
    escalation_flag: !validationPassed,
    destination_queue: !validationPassed ? 'Escalation Queue' : '',
    escalation_reason: !validationPassed ? 'Invalid or incomplete LLM output: ' + errors.join('; ') : ''
  }
}];

// ============================================================
// Node 5: Routing Logic
// Deterministic category-to-queue mapping with keyword
// override for IT/Security on auth-related questions.
// ============================================================

const item = $input.first().json;

// Skip routing if already escalated by validation
if (item.escalation_flag === true) {
  return [{ json: item }];
}

const CATEGORY_QUEUE_MAP = {
  'Bug Report': 'Engineering',
  'Feature Request': 'Product',
  'Billing Issue': 'Billing',
  'Incident/Outage': 'Engineering',
  'Technical Question': 'General Support'
};

let destinationQueue = CATEGORY_QUEUE_MAP[item.category] || 'General Support';

// Override for auth/security-related Technical Questions
if (item.category === 'Technical Question') {
  const authKeywords = ['sso', 'okta', 'saml', 'oauth', 'authentication',
    'identity provider', 'permissions', 'auth', 'login', 'credential',
    'mfa', 'two-factor', '2fa', 'ldap', 'active directory'];
  const msgLower = (item.raw_message || '').toLowerCase();
  const hasAuthKeyword = authKeywords.some(kw => msgLower.includes(kw));
  if (hasAuthKeyword) {
    destinationQueue = 'IT/Security';
  }
}

return [{
  json: {
    ...item,
    destination_queue: destinationQueue
  }
}];

// ============================================================
// Node 6: Escalation Check
// Determines if the request needs human review based on
// confidence threshold, outage indicators, billing amount,
// or prior validation failure.
// ============================================================

const item = $input.first().json;
const reasons = [];

// Already flagged by validation
if (item.escalation_flag === true) {
  reasons.push(item.escalation_reason || 'Validation failure');
}

// Low confidence
if (item.confidence_score < 0.70) {
  reasons.push(`Low confidence score: ${item.confidence_score}`);
}

// Incident/Outage category
if (item.category === 'Incident/Outage') {
  reasons.push('Category is Incident/Outage — requires immediate human review');
}

// Outage keyword detection
const outageKeywords = ['outage', 'down for all users', 'multiple users affected',
  'not loading', 'service down', 'system down', 'stopped loading',
  'stopped working', 'completely down'];
const msgLower = (item.raw_message || '').toLowerCase();
for (const kw of outageKeywords) {
  if (msgLower.includes(kw)) {
    reasons.push(`Outage indicator detected: "${kw}"`);
    break;
  }
}

// Billing discrepancy > $500
if (item.category === 'Billing Issue') {
  const amounts = (item.raw_message || '').match(/\$([\d,]+\.?\d*)/g);
  if (amounts && amounts.length >= 2) {
    const values = amounts.map(a => parseFloat(a.replace(/[$,]/g, ''))).sort((a, b) => b - a);
    const discrepancy = values[0] - values[1];
    if (discrepancy > 500) {
      reasons.push(`Billing discrepancy of $${discrepancy} exceeds $500 threshold`);
    }
  }
}

const shouldEscalate = reasons.length > 0;

return [{
  json: {
    ...item,
    escalation_flag: shouldEscalate,
    escalation_reason: shouldEscalate ? reasons.join('; ') : '',
    destination_queue: shouldEscalate ? 'Escalation Queue' : item.destination_queue
  }
}];

// ============================================================
// Node 7: Finalize Structured Record
// Builds the clean output record before branching to Sheets.
// Running here ensures Respond to Webhook always has data
// even if Google Sheets credentials are not yet configured.
// ============================================================

const item = $input.first().json;

const structuredRecord = {
  id: item.request_id,
  source: item.source,
  category: item.category,
  priority: item.priority,
  confidence_score: item.confidence_score,
  core_issue: item.core_issue,
  extracted_entities: item.extracted_entities,
  urgency_signal: item.urgency_signal,
  destination_queue: item.destination_queue,
  escalation_flag: item.escalation_flag,
  escalation_reason: item.escalation_reason || '',
  human_summary: item.human_summary,
  raw_message: item.raw_message,
  timestamp: item.timestamp
};

return [{ json: structuredRecord }];
